import{_ as o,o as t,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse(`{"title":"8. Consultation About Major Workplace Change","description":"","frontmatter":{"title":"8. Consultation About Major Workplace Change","eba":"Children's Services Award 2010","topics":["hours","employment","termination","consultation"]},"headers":[],"relativePath":"ebas/childrens-services/consultation-disputes/8-consultation-about-major-workplace-change.md","filePath":"ebas/childrens-services/consultation-disputes/8-consultation-about-major-workplace-change.md"}`),r={name:"ebas/childrens-services/consultation-disputes/8-consultation-about-major-workplace-change.md"};function s(i,e,l,c,p,u){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_8-consultation-about-major-workplace-change" tabindex="-1">8. Consultation About Major Workplace Change <a class="header-anchor" href="#_8-consultation-about-major-workplace-change" aria-label="Permalink to &quot;8. Consultation About Major Workplace Change&quot;">​</a></h1><p>[8---Consultation regarding major workplace change renamed and substituted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/pr546288.htm" target="_blank" rel="noreferrer">PR546288</a>, 8---Consultation renamed and substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr610286.htm" target="_blank" rel="noreferrer">PR610286</a> ppc 01Nov18]</p><ol><li><p>If an employer makes a definite decision to make major changes in production, program, organisation, structure or technology that are likely to have significant effects on employees, the employer must:</p><p>a. give notice of the changes to all employees who may be affected by them and their representatives (if any); and</p><p>b. discuss with affected employees and their representatives (if any):</p><pre><code>i.  the introduction of the changes; and

ii. their likely effect on employees; and

iii. measures to avoid or reduce the adverse effects of the
     changes on employees; and
</code></pre><p>c. commence discussions as soon as practicable after a definite decision has been made.</p></li><li><p>For the purposes of the discussion under clause 8.1(b), the employer must give in writing to the affected employees and their representatives (if any) all relevant information about the changes including:</p><p>a. their nature; and</p><p>b. their expected effect on employees; and</p><p>c. any other matters likely to affect employees.</p></li><li><p>Clause 8.2 does not require an employer to disclose any confidential information if its disclosure would be contrary to the employer&#39;s interests.</p></li><li><p>The employer must promptly consider any matters raised by the employees or their representatives about the changes in the course of the discussion under clause 8.1(b).</p></li><li><p>In clause 8:</p></li></ol><p><strong>significant effects</strong>, on employees, includes any of the following:</p><p>a. termination of employment; or</p><p>b. major changes in the composition, operation or size of the employer&#39;s workforce or in the skills required; or</p><p>c. loss of, or reduction in, job or promotion opportunities; or</p><p>d. loss of, or reduction in, job tenure; or</p><p>e. alteration of hours of work; or</p><p>f. the need for employees to be retrained or transferred to other work or locations; or</p><p>g. job restructuring.</p><ol><li>Where this award makes provision for alteration of any of the matters defined at clause 8.5, such alteration is taken not to have significant effect.</li></ol><p>Plain language terms: major change consultation, restructure consultation.</p>`,13)])])}const m=o(r,[["render",s]]);export{h as __pageData,m as default};
